sp_widget.client_script:
function ($scope, $rootScope,spAriaFocusManager, $http, amb,$timeout, spUtil, $location, $window, nowAttachmentHandler, $log, spAriaUtil, spModal, $uibModal, spNavStateManager) {
	/* widget controller */
	var c = this;
	$scope.submitting = false;
	var g_form;

	angular.element('.modal-footer').css({display:'none'});

	$scope.initiatingTemplate = false;
	$scope.templateStarted = false;
	$scope.btnCancelClick = function(){
		// close modal window
		$scope.$parent.buttonClicked($scope.$parent.options.buttons[0]);
	}

	$scope.lnkTaskOpenClick = function(){
		// close modal window
		$scope.$parent.buttonClicked($scope.$parent.options.buttons[0]);
	}

	$scope.btnStartButton = function(){
		// STRY0100724: DEV Story- Performance Improvements -  Running Templates and implify
		if(g_form){
			$scope.submitting = true;
			if(g_form.submit('start_template')){
				$scope.initiatingTemplate = true;
				$(".showAlert").hide().show('medium');
				c.data.currentStep = 'StartTemplate';
				var table = 'x_153465_discovert_route_task_instance';
				var filter = 'u_parent_template='+ c.data.process_template_sys_id + '^parentISEMPTY';
				// Start watching for task looking for an event for the Template ID before starting the template
				if (c.watcher)
					c.watcher.unsubscribe();
				c.watcher = watcher(table, filter, taskFromTemplateStarted);

			}
			$scope.submitting = false;
		}		
	}

	// Make sure to include amb as a provider in your client controller
	// function to setup a watcher
	function watcher(table, filter, callback){
		var channel = amb.getChannelRW(table, filter);
		amb.connect();
		var watch = channel.subscribe(callback)
		return watch;
	}

	function taskFromTemplateStarted(message){
		c.data.linkToTopTaskForTemplateStarted = '../discovertaskerportal?id=discovertasker_taskdetails&table=x_153465_discovert_route_task_instance&sys_id=' + message.data.sys_id + '&spa=1';
		c.data.taskDisplayValue = message.data.display_value;
		$scope.initiatingTemplate = false;
		$scope.templateStarted = true;
		// done with record watcher unsubscribe	
		c.watcher.unsubscribe();
	}

	function initForm(gFormInstance) {
		if (gFormInstance.getTableName() != undefined &&
				gFormInstance.getTableName() == $scope.data.f.table) {
			g_form = gFormInstance;
		}
	}

	$scope.$on('spModel.gForm.env.created', function(e, gFormInstance) {
		initForm(gFormInstance);
	});

	// remove record watcher when form closes
	$scope.$on('$destroy', function() {
		if (c.watcher)
			c.watcher.unsubscribe();
	});
}

sp_widget.css:
//------------------------------------------------------------------------------------------------------------------------
// COMPANY: DISCOVER TECHNOLOGIES
// CUSTOMIZED BY: KARINA TORRES 
//------------------------------------------------------------------------------------------------------------------------
//------------------------------------------------------------------------------------------------------------------------
// 2.5.21 | 09.10.2020 | KT | UI  | STRY0074067: TECH - Tasker - Unified CSS on widgets (Internal Story, PO story needed)
//------------------------------------------------------------------------------------------------------------------------


//------------------------------------------------------------------------------------------------------------------------
// CUSTOM
//------------------------------------------------------------------------------------------------------------------------


/* SECTIONS & FORMS */
//------------------------------------------------------------------------------------------------------------------------
.ng-isolate-scope .h4.ng-binding{
  font-weight: 400 !important;
  font-family: "SourceSansPro", Helvetica, Arial, sans-serif; //'Lucida Sans Unicode';
  padding-left: 5px;
	border-left-style: solid;
	border-left-color: $primary;
	border-left-width: 5px;
	color: $primary;
	padding-top: 8px;
	padding-bottom: 5px;
}

fieldset.ng-scope{
  margin-top: 5px;
}

label{
	//font-weight: 100!important;
  color: $primary;
}


/* DURATION */
//------------------------------------------------------------------------------------------------------------------------

#dur-minutes,
#dur-seconds { 
  visibility: hidden!important;
}

#dur-days,
#dur-hours { 
  width: 40px!important
}


//------------------------------------------------------------------------------------------------------------------------
// OOTB FORM WIDGET
//------------------------------------------------------------------------------------------------------------------------


.btn-form-menu {
	vertical-align: inherit;
  padding: inherit;
  background: none;
}

.panel-title {
  word-wrap: break-word;
}

.panel-heading {
  .dropdown-menu {
    a {
      white-space: normal;
    }
  }
}

.sc-field-error-label {
  margin-right: .5em;
  display: inline-block;
  background-color: $sc-field-error-color;
}

.comment {
	font-weight: bold;
	margin-top: 2px;
	margin-bottom: 2px;
}
.mce-panel, .mce-btn {
	background-image: none;
	background-color: #f0f3f4;
}

.action-btn {
  margin-right: 5px;
}

.timeline-container {
   max-height: 50vh;
   height: 100%;
   overflow-y: auto;
}

.panel .panel {
    height: auto !important;
}

.attachment-button {
  .glyphicon-paperclip {
    font-size: 18px;
  }
}

.dropdown {
  .glyphicon-menu-hamburger:focus {
 		outline: thin dotted;
		outline: 5px auto $input-border-focus;
		outline-offset: -2px; 
	}
}

.empty-state-wrapper {
  width: 100%;
  height: 100%;
  align-items: center;
  display: flex;
  flex-direction: column;
  padding: 10vh 20px 20px;

  .empty-state {
    border: 1px solid #e7e9eb;
    border-radius: 10px;
    max-width: 700px;
    padding: 30px 40px 20px;
    position: relative;

    .empty-state-badge {
      top: -36px;
      left: 50%;
      position: absolute;
      height: 72px;
      width: 72px;
      -webkit-align-items: center;
      -ms-flex-align: center;
      align-items: center;
      border-radius: 100%;
      color: #ffffff;
      display: -webkit-flex;
      display: -ms-flexbox;
      display: flex;
      font-size: 40px;
      -webkit-justify-content: center;
      -ms-flex-pack: center;
      justify-content: center;
      margin-left: -36px;
      text-align: center;
    }

    .empty-state-header {
      font-size: 30px;
      text-align: center;
      color: #343d47;
    }

    .empty-state-content {
      ul {
        list-style: disc outside;
        margin: 0 0 10px 0;
        padding: 0 0 0 30px;
      }
    }
  }
}

.text-success-alt {
	background-color: $state-success-text;
}

.text-info-alt {
	background-color: $state-info-text;
}

sp_widget.script:
// Copyrights belong to Discover Technologies LLC. © 2019 Discover Technologies LLC
// Script Continued Below
//------------------------------------------------------------------------------------------------------------------------
// WIDGET BASE: TASKER DATA TABLE
// COMPANY: DISCOVER TECHNOLOGIES
// CUSTOMIZED BY: Karina Torres
/**
 * Description
 * This widget opens when you click on "Run Process Template" 
 * @method anonymous-0
 * @author Karina Torres [KTorres]
 * @memberof x_153465_discovert.module:sp_widget
 * @returns {undefined}
 */
//------------------------------------------------------------------------------------------------------------------------
//
// 2.7.0 | 07.05.2021 | raj | STRY0100724: DEV Story- Performance Improvements -  Running Templates and implify
//                                   Updates in Server, Client and HTML
// 2.7.0 | 2021-08-10 | mmcc | STRY0104983 - Stretch- Technical Debt - Update CSS to organize into proper hierarchy of CSS
// 											In CSS, selector .taskform-classification-banner removed, not used. 
// 											 Selector .assignmentgroup-banner removed, not used.
//											 Selector #sp_formfield_status removed, was commented out.
//											In Server script, fixed white space issues, format whole script.
//                                          Changes in CSS and Server script

//------------------------------------------------------------------------------------------------------------------------

(function($sp, input, data, options, gs) {
    /* populate the 'data' object */

    // STRY0098385 - remove Cancel button from Mobile 
    data.page_id = $sp.getParameter("id");

    // rebuild the widget to run using template instance
    // RJ - TUP - STRY0068618 
    // STRY0090951 - Mobile – Run Template action from swipe action and from UI action on Template form
    data.process_template_sys_id = (input || {}).process_template_sys_id || (options || {}).process_template_sys_id || $sp.getParameter('process_template_sys_id');
    // STRY0090951 - Mobile – Run Template action from swipe action and from UI action on Template form
    if (input == undefined || input.currentStep == undefined) {
        data.canAttach = false;
        // build the Template Instance Form here
        data.f = $sp.getForm("x_153465_discovert_discover_routing_runtime",
            "-1", 'routing_template_ref=' + data.process_template_sys_id,
            "Default View");
        data.canRun = new uiConditionCheck().startTemplateUIAction(data.process_template_sys_id, '');

        data.currentStep = 'enterInfo';
    }


})($sp, input, data, options, gs);
